INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00432', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '為促進原住民就業，保障原住民工作權及經濟生活，以下敘述何者錯誤？', '["原住民族工作權保障法保障對象為居住於原住民族地區以外之都市原住民", "各級政府機關、公立學校及公營事業機構應依循比例進用原則僱用原住民", "政府應依原住民群體工作習性，輔導原住民設立各種性質之原住民合作社", "依政府採購法得標之廠商，於國內員工總人數逾一百人者，應於履約期間僱用原住民"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00433', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '以下何者不屬於原住民族傳統智慧創作保護條例所保護的範圍？', '["原住民族傳統之宗教祭儀", "原住民族傳統之舞蹈", "原住民族傳統之神話", "原住民族傳統之服飾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00434', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '關於劃編原住民保留地，以下敘述何者錯誤？', '["原則為針對原住民迄今仍使用之公有土地", "目的為輔導原住民宗教團體取得宗教建築設施使用土地權利", "因不可抗力或天然災害等因素致使用中斷，仍可例外劃編", "依水利法規定屬於尋常洪水位行水區域之土地，不得劃編"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00435', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '關於原住民民族別之認定，以下敘述何者錯誤？', '["原住民父母屬於不同民族別者，其子女之民族別，未成年時得由法定代理人協議", "父母僅一方為原住民，具有原住民身分之子女，從具原住民身分之父或母之民族別", "行政院核定新民族別時，已註記民族別之成年人得依個人意願申請變更為該民族別", "原住民女子與原住民男子之非婚生子女，未經生父認領者，從父或母之民族別"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00436', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '關於8月1日原住民族日之由來，以下敘述何者正確？', '["紀念我國修憲將山胞正名為原住民", "紀念我國立法通過原住民族基本法", "紀念聯合國通過原住民族權利宣言", "紀念聯合國成立原住民族常設論壇"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00437', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族教育法，以下敘述何者錯誤？', '["所謂民族教育，係指依原住民族文化特性，對原住民學生所實施之民族知識教育", "所謂一般教育，係指民族教育外，對原住民學生所實施之一般性質教育", "所謂原住民族學校，係指原住民學生達一定人數或比率之高級中等以下學校", "所謂原住民教育班，係指為原住民學生教育需要，於一般學校中開設之班級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00438', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '關於原住民族歲時祭儀之放假，以下敘述何者錯誤？', '["其應放假一至三日之日期，由原住民族委員會公告", "為各該原住民族勞工之法定休假日，雇主應予放假且工資照給", "屬於紀念日及節日實施辦法中規定之民俗節日", "雇主未依法給假或給薪者，除可處罰鍰外，並將公布違法事業單位名稱"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00439', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '原住民族委員會補助原住民族地區基本設施之維持，以下何者不屬於支用項目範圍？', '["依法令約聘僱人員之薪俸、加給、獎金、加班值班費等等", "購置辦公室內部各類設備之經費，但不得購置汽（機）車", "水電、通訊、租金、一般事務、設備養護及其他行政事務費用", "推展原住民族相關業務之員工自強活動、旅遊及國外旅費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00440', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '關於總統府原住民族歷史正義與轉型正義委員會之任務，以下敘述何者錯誤？', '["蒐集、彙整並揭露歷來因外來政權或移民所導致原住民族與原住民權利受侵害、剝奪之歷史真相", "對原住民族與原住民受侵害、剝奪之權利，規劃回復、賠償或補償之行政、立法或其他措施", "落實行政院原住民族基本法推動會所做成之行政、立法或其他措施之規劃建議", "與原住民族歷史正義與轉型正義有關事項之資訊蒐集、意見彙整與協商討論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00441', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', 'Somescientistsreportthatyawningcanmakeusmore__________.Whenweyawn,webreathedeeplyand stretchthemusclesinourfaceandneck.', '["alert", "alien", "alight", "alike"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
